  .btn-ghost:hover{
    background: rgba(11, 94, 215, .06);
  }

  .btn-lg{
    padding: 12px 18px;
    font-size: 15px;
    border-radius: 14px;
  }

  .adv-badges{
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 8px;
  }

  .badge{
    background: rgba(11,94,215,.10);
    border: 1px solid rgba(11,94,215,.18);
    color: #0b3b84;
    padding: 6px 10px;
    border-radius: 999px;
    font-size: 12px;
    font-weight: 800;
  }

  .adv-content{
    padding: 22px 14px 30px;
  }

  .adv-grid{
    max-width: 1100px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: 1fr;
    gap: 14px;
  }

  @media (min-width: 720px){
    .adv-grid{ grid-template-columns: repeat(2, minmax(0, 1fr)); }
    .adv-title{ font-size: 32px; }
  }

  @media (min-width: 1024px){
    .adv-grid{ grid-template-columns: repeat(3, minmax(0, 1fr)); }
  }

  .adv-card{
    border: 1px solid var(--border);
    background: #fff;
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    padding: 14px 14px 12px;
    transition: transform .18s ease, box-shadow .18s ease, border-color .18s ease;
  }

  .adv-card:hover{
    transform: translateY(-2px);
    box-shadow: 0 14px 32px rgba(0,0,0,.09);
    border-color: rgba(11, 94, 215, .35);
  }

  .adv-card__title{
    margin: 0 0 8px 0;
    font-size: 16px;
    font-weight: 900;
    letter-spacing: -0.2px;
  }

  .adv-card__text{
    margin: 0 0 10px 0;
    color: var(--muted);
    line-height: 1.55;
    font-size: 14px;
  }

  .adv-list{
    margin: 0;
    padding-left: 18px;
    color: var(--text);
    font-size: 13.5px;
    line-height: 1.55;
  }

  .adv-list li{
    margin: 4px 0;
  }

  .adv-faq{
    max-width: 1100px;
    margin: 18px auto 0;
    border-top: 1px solid var(--border);
    padding-top: 18px;
  }

  .adv-section-title{
    margin: 0 0 10px 0;
    font-size: 18px;
    font-weight: 900;
  }

  .faq-item{
    border: 1px solid var(--border);
    background: #fff;
    border-radius: 14px;
    padding: 10px 12px;
    margin-bottom: 10px;
  }

  .faq-item summary{
    cursor: pointer;
    font-weight: 900;
    color: var(--text);
    list-style: none;
  }

  .faq-item summary::-webkit-details-marker{ display: none; }

  .faq-item p{
    margin: 10px 0 0 0;
    color: var(--muted);
    line-height: 1.55;
    font-size: 14px;
  }

  .adv-final-cta{
    max-width: 1100px;
    margin: 18px auto 0;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    background: linear-gradient(180deg, rgba(11,94,215,.08), rgba(11,94,215,0));
    box-shadow: var(--shadow);
  }

  .adv-final-cta__inner{
    padding: 16px 14px;
    text-align: left;
  }

  .adv-final-cta__title{
    margin: 0 0 6px 0;
    font-size: 18px;
    font-weight: 900;
  }

  .adv-final-cta__text{
    margin: 0 0 12px 0;
    color: var(--muted);
    line-height: 1.55;
    font-size: 14px;
    max-width: 900px;
  }

  .adv-note{
    margin: 10px 0 0 0;
    color: var(--muted);
    font-size: 13px;
  }
</style>


